"use client";

import { useRef, useEffect, useState, useCallback } from "react";
import Typed from "typed.js";
import "./particle-canvas.css";
import {
  AboutSection,
  ExperienceSection,
  ProjectsSection,
  SkillsSection,
  ContactSection,
} from "./sections";
import type { SectionConfig } from "./sections";

/* ═══════════════════════════════════════
   Section setup — hero (index 0) uses Typed.js overlay,
   remaining sections use particle dot-matrix text.
   ═══════════════════════════════════════ */
const HERO_LABEL = "00 // hero";

const TEXT_SECTIONS: SectionConfig[] = [
  AboutSection,
  ExperienceSection,
  ProjectsSection,
  SkillsSection,
  ContactSection,
];

const ALL_LABELS = [HERO_LABEL, ...TEXT_SECTIONS.map((s) => s.label)];
const TOTAL_SECTIONS = ALL_LABELS.length; /* 6 */

/* ═══════════════════════════════════════
   Text-to-pixel sampling (fine grid)
   ═══════════════════════════════════════ */
function sampleTextPixels(
  lines: string[],
  fontSize: number,
  lineHeight: number,
  letterSpacing: number,
  canvasW: number,
  canvasH: number,
  gridStep: number,
  fontFamily: string,
): Set<string> {
  const off = document.createElement("canvas");
  off.width = canvasW;
  off.height = canvasH;
  const octx = off.getContext("2d")!;

  octx.fillStyle = "#fff";
  octx.font = `400 ${fontSize}px ${fontFamily}`;
  octx.textBaseline = "top";

  try {
    (octx as unknown as Record<string, string>).letterSpacing = `${letterSpacing}px`;
  } catch {
    /* noop */
  }

  const lh = fontSize * lineHeight;
  const totalH = lines.length * lh;
  const startY = (canvasH - totalH) / 2;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (!line) continue;
    const m = octx.measureText(line);
    octx.fillText(line, (canvasW - m.width) / 2, startY + i * lh);
  }

  const img = octx.getImageData(0, 0, canvasW, canvasH);
  const set = new Set<string>();
  const cols = Math.floor(canvasW / gridStep);
  const rows = Math.floor(canvasH / gridStep);

  for (let gy = 0; gy < rows; gy++) {
    for (let gx = 0; gx < cols; gx++) {
      const cx = gx * gridStep + Math.floor(gridStep / 2);
      const cy = gy * gridStep + Math.floor(gridStep / 2);
      if (cx < canvasW && cy < canvasH) {
        const idx = (cy * canvasW + cx) * 4;
        if (img.data[idx + 3] > 40) {
          set.add(`${gx},${gy}`);
        }
      }
    }
  }

  return set;
}

/* ═══════════════════════════════════════
   Easing
   ═══════════════════════════════════════ */
function easeInOutCubic(t: number): number {
  return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
}

/* ═══════════════════════════════════════
   Particle types
   ═══════════════════════════════════════ */
interface SectionTarget {
  x: number;
  y: number;
  isText: boolean;
}

interface Particle {
  x: number;
  y: number;
  opacity: number;
  targets: SectionTarget[];
}

/* ═══════════════════════════════════════
   Component
   ═══════════════════════════════════════ */
export default function ParticleCanvas() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const rafRef = useRef(0);
  const indicatorRef = useRef<HTMLDivElement>(null);
  const typedElRef = useRef<HTMLSpanElement>(null);
  const heroOverlayRef = useRef<HTMLDivElement>(null);
  const heroVisibleRef = useRef(true);
  const [, forceRender] = useState(0);

  /* Track hero visibility via ref (fast) + occasional React state for DOM class */
  const setHeroVisible = useCallback(
    (v: boolean) => {
      if (heroVisibleRef.current === v) return;
      heroVisibleRef.current = v;
      /* Directly toggle class for zero-lag response */
      heroOverlayRef.current?.classList.toggle("visible", v);
    },
    [],
  );

  /* ── Typed.js for hero section ── */
  useEffect(() => {
    if (!typedElRef.current) return;
    const typed = new Typed(typedElRef.current, {
      strings: [
        "Hi!",
        "My name is Kalyankumar",
        "I build things for the upcoming AI world!",
      ],
      typeSpeed: 60,
      backSpeed: 40,
      loop: true,
      showCursor: true,
      cursorChar: "|",
    });
    return () => typed.destroy();
  }, []);

  /* ── Particle canvas ── */
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext("2d")!;
    const dpr = Math.min(window.devicePixelRatio || 1, 2);
    const W = window.innerWidth;
    const H = window.innerHeight;

    canvas.width = W * dpr;
    canvas.height = H * dpr;
    canvas.style.width = `${W}px`;
    canvas.style.height = `${H}px`;
    ctx.scale(dpr, dpr);

    const cX = W / 2;
    const cY = H / 2;

    /* ── Fine dot-matrix grid — small enough for readable text ── */
    const dotSize = W < 600 ? 3 : W < 1024 ? 4 : 5;
    const gap = 2;
    const gridStep = dotSize + gap;
    const cols = Math.floor(W / gridStep);
    const rows = Math.floor(H / gridStep);
    const oX = (W - cols * gridStep + gap) / 2;
    const oY = (H - rows * gridStep + gap) / 2;
    const N = cols * rows;

    /* ── Pre-render dot sprite for performance (~20K drawImage > ~20K arc) ── */
    const spriteSize = dotSize + 2; /* 1px margin each side */
    const dotSprite = document.createElement("canvas");
    dotSprite.width = spriteSize * dpr;
    dotSprite.height = spriteSize * dpr;
    const dctx = dotSprite.getContext("2d")!;
    dctx.scale(dpr, dpr);
    dctx.fillStyle = "#ffffff";
    dctx.beginPath();
    dctx.arc(spriteSize / 2, spriteSize / 2, dotSize / 2, 0, Math.PI * 2);
    dctx.fill();

    /* Enable scrolling */
    document.body.style.overflow = "auto";
    document.body.style.overflowX = "hidden";
    document.body.style.height = `${TOTAL_SECTIONS * 100}vh`;

    /* Wait for fonts, then sample text and start animation */
    document.fonts.ready.then(() => {
      const computedFont = getComputedStyle(document.documentElement)
        .getPropertyValue("--font-mono")
        .trim();
      const fontFamily = computedFont
        ? `${computedFont}, 'JetBrains Mono', monospace`
        : "'JetBrains Mono', 'SF Mono', monospace";

      /* ── Build targets for all 6 sections ── */
      const allTargets: SectionTarget[][] = [];

      /* Section 0: hero — all ambient (Typed.js handles display) */
      const heroTargets: SectionTarget[] = [];
      for (let gy = 0; gy < rows; gy++) {
        for (let gx = 0; gx < cols; gx++) {
          heroTargets.push({
            x: oX + gx * gridStep + dotSize / 2,
            y: oY + gy * gridStep + dotSize / 2,
            isText: false,
          });
        }
      }
      allTargets.push(heroTargets);

      /* Sections 1–5: particle dot-matrix text */
      for (const section of TEXT_SECTIONS) {
        const fontSize = Math.max(
          10,
          Math.round(section.fontSizeBase * Math.min(1, W / 1440)),
        );
        const textSet = sampleTextPixels(
          section.lines,
          fontSize,
          section.lineHeight,
          section.letterSpacing,
          W,
          H,
          gridStep,
          fontFamily,
        );

        const targets: SectionTarget[] = [];
        for (let gy = 0; gy < rows; gy++) {
          for (let gx = 0; gx < cols; gx++) {
            targets.push({
              x: oX + gx * gridStep + dotSize / 2,
              y: oY + gy * gridStep + dotSize / 2,
              isText: textSet.has(`${gx},${gy}`),
            });
          }
        }
        allTargets.push(targets);
      }

      /* ── Create particles at center ── */
      const particles: Particle[] = [];
      for (let i = 0; i < N; i++) {
        particles.push({
          x: cX + (Math.random() - 0.5) * 8,
          y: cY + (Math.random() - 0.5) * 8,
          opacity: 0,
          targets: allTargets.map((st) => st[i]),
        });
      }

      /* ── Animation state ── */
      let lastScrollY = 0;
      let scrollVelocity = 0;
      let entryPhase = true;
      let entryStart = 0;
      const ENTRY_DUR = 2000;
      let time = 0;
      let currentLabel = ALL_LABELS[0];
      let prevActiveIdx = 0;

      const dotEls =
        indicatorRef.current?.querySelectorAll<HTMLDivElement>(".pc-dot");

      /* ── RAF loop ── */
      const tick = (now: number) => {
        time = now * 0.001;

        const scrollY = window.scrollY;
        scrollVelocity =
          scrollVelocity * 0.85 + Math.abs(scrollY - lastScrollY) * 0.15;
        lastScrollY = scrollY;

        const progress = scrollY / H;
        const sectionA = Math.min(Math.floor(progress), TOTAL_SECTIONS - 1);
        const sectionB = Math.min(sectionA + 1, TOTAL_SECTIONS - 1);
        const t =
          sectionA === sectionB ? 0 : Math.min(1, progress - sectionA);
        const eased = easeInOutCubic(t);

        const activeSec = t > 0.5 ? sectionB : sectionA;

        /* Show/hide hero overlay */
        if (activeSec !== prevActiveIdx) {
          prevActiveIdx = activeSec;
          setHeroVisible(activeSec === 0);
        }

        const chaos =
          Math.sin(t * Math.PI) * Math.min(scrollVelocity * 0.4, 20);

        /* Update section label + dots */
        const newLabel = ALL_LABELS[activeSec];
        if (newLabel !== currentLabel) {
          currentLabel = newLabel;
          if (indicatorRef.current) {
            const labelEl =
              indicatorRef.current.querySelector<HTMLDivElement>(".pc-label");
            if (labelEl) labelEl.textContent = currentLabel;
          }
          dotEls?.forEach((dot, idx) => {
            dot.classList.toggle("active", idx === activeSec);
          });
        }

        /* ── Clear ── */
        ctx.clearRect(0, 0, W, H);

        /* ── Update & draw ── */
        const halfSprite = spriteSize / 2;
        for (let i = 0; i < N; i++) {
          const p = particles[i];
          const fromT = p.targets[sectionA];
          const toT = p.targets[sectionB];

          let tgtX = fromT.x * (1 - eased) + toT.x * eased;
          let tgtY = fromT.y * (1 - eased) + toT.y * eased;
          const isTextA = fromT.isText;
          const isTextB = toT.isText;

          const opaA = isTextA ? 0.88 : 0.025;
          const opaB = isTextB ? 0.88 : 0.025;
          let tgtOpacity = opaA * (1 - eased) + opaB * eased;

          if (chaos > 0.5) {
            tgtX += Math.sin(i * 0.37 + time * 3) * chaos;
            tgtY += Math.cos(i * 0.53 + time * 3) * chaos;
          }

          const centerPull = Math.sin(t * Math.PI) * 0.15;
          tgtX = tgtX * (1 - centerPull) + cX * centerPull;
          tgtY = tgtY * (1 - centerPull) + cY * centerPull;

          if (entryPhase) {
            if (!entryStart) entryStart = now;
            const entryT = Math.min(1, (now - entryStart) / ENTRY_DUR);
            const stagger = (i / N) * 0.35;
            const pT = Math.max(
              0,
              Math.min(1, (entryT - stagger) / (1 - stagger)),
            );
            const ee = 1 - Math.pow(1 - pT, 3);
            tgtX = cX + (tgtX - cX) * ee;
            tgtY = cY + (tgtY - cY) * ee;
            tgtOpacity *= ee;
            if (entryT >= 1) entryPhase = false;
          }

          p.x += (tgtX - p.x) * 0.065;
          p.y += (tgtY - p.y) * 0.065;
          p.opacity += (tgtOpacity - p.opacity) * 0.08;

          p.x += Math.sin(time * 0.8 + i * 0.1) * 0.08;
          p.y += Math.cos(time * 0.6 + i * 0.15) * 0.08;

          /* Draw via pre-rendered sprite */
          if (p.opacity > 0.005) {
            ctx.globalAlpha = p.opacity;
            ctx.drawImage(
              dotSprite,
              p.x - halfSprite,
              p.y - halfSprite,
              spriteSize,
              spriteSize,
            );
          }
        }

        rafRef.current = requestAnimationFrame(tick);
      };

      rafRef.current = requestAnimationFrame(tick);
    });

    return () => {
      cancelAnimationFrame(rafRef.current);
      document.body.style.overflow = "";
      document.body.style.overflowX = "";
      document.body.style.height = "";
    };
  }, [setHeroVisible]);

  return (
    <>
      <canvas ref={canvasRef} className="pc-canvas" />

      {/* Hero Typed.js overlay */}
      <div ref={heroOverlayRef} className="pc-hero-overlay visible">
        <span ref={typedElRef} className="pc-hero-typed" />
      </div>

      {/* Scroll spacers */}
      <div className="pc-sections">
        {ALL_LABELS.map((_, i) => (
          <section key={i} className="pc-section" data-section={i} />
        ))}
      </div>

      {/* Section indicator */}
      <div ref={indicatorRef} className="pc-indicator">
        <div className="pc-label">{ALL_LABELS[0]}</div>
        <div className="pc-dots">
          {ALL_LABELS.map((_, i) => (
            <div key={i} className={`pc-dot${i === 0 ? " active" : ""}`} />
          ))}
        </div>
      </div>
    </>
  );
}
